class SWIMNode:
    def __init__(self, node_id, all_nodes):
        self.node_id = node_id
        self.members = {n: {'status': 'alive', 'incarnation': 0}
                       for n in all_nodes}
        self.suspects = {}
        self.piggyback = []

    def tick(self, current_time):
        target = random.choice([n for n in self.members
                                if n != self.node_id
                                and n not in self.suspects])
        ack = self._ping(target)
        if ack:
            self._exchange_piggyback(target)
        else:
            indirect_probers = random.sample(
                [n for n in self.members
                 if n not in (self.node_id, target)],
                min(K, len(self.members) - 2))
            indirect_ack = False
            for prober in indirect_probers:
                if self._ping_proxy(prober, target):
                    indirect_ack = True
                    self._exchange_piggyback(prober)
                    break

            if not indirect_ack:
                inc = self.members[target]['incarnation'] + 1
                self.suspects[target] = (inc, current_time + SUSPECT_TIMEOUT)
                self.piggyback.append(('suspect', target, inc))
                self.members[target]['status'] = 'suspect'

        expired = [n for n, (_, t) in self.suspects.items()
                   if current_time >= t]
        for node in expired:
            del self.suspects[node]
            del self.members[node]

    def _ping(self, target):
        pass

    def _ping_proxy(self, prober, target):
        pass

    def receive_gossip(self, from_node, updates):
        for update in updates:
            kind, node_id, incarnation = update
            current = self.members.get(node_id, {})
            if incarnation > current.get('incarnation', -1):
                if kind == 'alive':
                    self.members[node_id] = {
                        'status': 'alive',
                        'incarnation': incarnation
                    }
                    if node_id in self.suspects:
                        del self.suspects[node_id]
                elif kind == 'suspect':
                    self.suspects[node_id] = (
                        incarnation, time.time() + SUSPECT_TIMEOUT)
                    self.members[node_id]['status'] = 'suspect'
                elif kind == 'confirm':
                    self.members[node_id] = {
                        'status': 'dead',
                        'incarnation': incarnation
                    }
